import { Warehouse, WarehouseRepository } from "./warehouse-repository";
import { AppError } from "../shared/app-error";

export class WarehouseService {
  constructor(private readonly repo: WarehouseRepository) {}

  async getWarehouse(id: string): Promise<Warehouse> {
    const warehouse = await this.repo.findById(id);
    if (!warehouse) {
      throw new AppError("WAREHOUSE_NOT_FOUND", `Warehouse ${id} not found`);
    }
    return warehouse;
  }

  async updateCapacity(id: string, newCapacity: number): Promise<void> {
    const warehouse = await this.getWarehouse(id);
    warehouse.capacity = newCapacity;
    await this.repo.save(warehouse);
  }
}

